    Yes { vaddr: usize, size: usize },
    No,
}

impl View for DoShootdown {
    type V = DoShootdownView;
    closed spec fn view(&self) -> DoShootdownView {
        match self {
            DoShootdown::Yes { vaddr, size } => DoShootdownView::Yes { vaddr: *vaddr, size: *size },
            DoShootdown::No => DoShootdownView::No,
        }
    }
}

